// --- External Authorization ---
// CreateExternalAuthorizationRequest Start passwordless grant issuance for an external identity and installation.
//
// Response fields: success, error_message, device_code, user_code, verification_uri, verification_uri_complete, expires_in, poll_interval, grant_duration_seconds.
// See https://docs.mindupload.app
func (c *Client) CreateExternalAuthorizationRequest(ctx context.Context, params CreateExternalAuthorizationRequestParams) (*Response, error) {
	if params.IdempotencyKey == "" {
		return nil, errors.New("idempotency_key is required")
	}
	if params.InstallationID == "" {
		return nil, errors.New("installation_id is required")
	}
	if params.ExternalSubject == "" {
		return nil, errors.New("external_subject is required")
	}
	if len(params.RequestedScopes) == 0 {
		return nil, errors.New("requested_scopes is required")
	}
	// Reject unsupported enum values locally before sending the request.
	for _, requestedScopeValue := range params.RequestedScopes {
		switch requestedScopeValue {
		case "clone:invoke", "clone:learn":
		default:
			return nil, errors.New("requested_scopes contains an unsupported value")
		}
	}
	return c.do(ctx, "create_external_authorization_request", structToMap(params))
}

