// ExternalAuthorizationStatus is a stable device-flow polling state.
type ExternalAuthorizationStatus string

const (
	ExternalAuthorizationPending   ExternalAuthorizationStatus = "pending"
	ExternalAuthorizationSlowDown  ExternalAuthorizationStatus = "slow_down"
	ExternalAuthorizationDenied    ExternalAuthorizationStatus = "denied"
	ExternalAuthorizationExpired   ExternalAuthorizationStatus = "expired"
	ExternalAuthorizationRevoked   ExternalAuthorizationStatus = "revoked"
	ExternalAuthorizationExchanged ExternalAuthorizationStatus = "exchanged"
)

const (
	defaultAuthorizationPoll = 5 * time.Second
	maximumPendingPoll       = 15 * time.Second
	maximumSlowDownPoll      = 30 * time.Second
	slowDownIncrement        = 5 * time.Second
	pollJitterRatio          = 0.2
)

const (
	defaultInvocationPoll              = 2 * time.Second
	maximumInvocationPoll              = 10 * time.Second
	externalInvocationProcessingStatus = "processing"
)

// invocationRetryStatuses are transient gateway faults worth replaying an
// idempotent invocation through; a slow in-request clone reply can surface as
// one of these before the receipt is ready.
var invocationRetryStatuses = map[int]bool{502: true, 503: true, 504: true}

// WaitForExternalAuthorization polls at the server-advised cadence until
// exchange succeeds or the provided context is canceled.
func (c *Client) WaitForExternalAuthorization(
	ctx context.Context, deviceCode string,
) (*Response, error) {
	pollInterval := defaultAuthorizationPoll
	// Poll sequentially because every response controls the next
	// server-advised delay.
	for {
		result, err := c.ExchangeExternalAuthorization(
			ctx, ExchangeExternalAuthorizationParams{DeviceCode: deviceCode},
		)
		if err != nil {
			return nil, err
		}
		status := ExternalAuthorizationStatus(result.String("status"))
		switch status {
		case ExternalAuthorizationExchanged:
			return result, nil
		case ExternalAuthorizationDenied, ExternalAuthorizationExpired, ExternalAuthorizationRevoked:
			return nil, &Error{
				Operation: "exchange_external_authorization",
				Message:   "external authorization ended with status: " + string(status),
				Response:  result.Data,
			}
		}
		serverInterval := defaultAuthorizationPoll
		if seconds, ok := result.Get("poll_interval").(float64); ok && seconds > 0 {
			serverInterval = time.Duration(seconds * float64(time.Second))
		}
		if status == ExternalAuthorizationSlowDown {
			pollInterval += slowDownIncrement
			if pollInterval > maximumSlowDownPoll {
				pollInterval = maximumSlowDownPoll
			}
		} else {
			pollInterval = pollInterval * 3 / 2
			if pollInterval > maximumPendingPoll {
				pollInterval = maximumPendingPoll
			}
		}
		if serverInterval > pollInterval {
			pollInterval = serverInterval
		}
		jitter := time.Duration(
			rand.Float64() * pollJitterRatio * float64(pollInterval),
		)
		if err := sleepCtx(ctx, pollInterval+jitter); err != nil {
			return nil, err
		}
	}
}

// WaitForExternalCloneInvocation invokes a clone and waits out slow in-request
// generation via idempotent retries, until the reply is ready or ctx is canceled.
//
// Because the invocation is idempotent on the params' idempotency key, re-sending
// the same event is safe: a still-generating call returns status "processing" (or
// a per-call timeout, connection failure, or transient gateway fault), and the
// finished result is replayed once ready. Pass a ctx with a deadline
// (context.WithTimeout) to bound the total wait; a deadline-less ctx polls until
// the reply is ready.
func (c *Client) WaitForExternalCloneInvocation(
	ctx context.Context, params InvokeExternalCloneParams,
) (*Response, error) {
	pollInterval := defaultInvocationPoll
	// Poll sequentially; the same idempotency key coalesces to one server-side
	// generation and one charge, so re-sending is safe.
	for {
		result, err := c.InvokeExternalClone(ctx, params)
		if err != nil {
			if ctx.Err() != nil {
				// The caller's own context was canceled or hit its deadline: stop.
				return nil, err
			}
			// A per-call timeout or connection failure means the reply may still be
			// generating server-side, and a transient gateway fault is worth replaying;
			// the same idempotency key makes the retry safe. Surface everything else
			// (4xx, 429, and a failed receipt, all of which carry no retry sentinel).
			var apiErr *Error
			switch {
			case errors.Is(err, ErrConnection), errors.Is(err, context.DeadlineExceeded):
				result = nil
			case errors.As(err, &apiErr) && invocationRetryStatuses[apiErr.Status]:
				result = nil
			default:
				return nil, err
			}
		}
		if result != nil && result.String("status") != externalInvocationProcessingStatus {
			return result, nil
		}
		if result != nil {
			if seconds, ok := result.Get("retry_after_seconds").(float64); ok && seconds > 0 {
				pollInterval = time.Duration(seconds * float64(time.Second))
			}
		}
		if pollInterval > maximumInvocationPoll {
			pollInterval = maximumInvocationPoll
		}
		jitter := time.Duration(rand.Float64() * pollJitterRatio * float64(pollInterval))
		if err := sleepCtx(ctx, pollInterval+jitter); err != nil {
			return nil, err
		}
	}
}
